noncompliant:
void function() {
    // Comment with line splice \
    and this line becomes part of comment
    int x = 5; // This line is commented out due to splice above!
}

compliant:
#define LOG_FAILURE(CONDITION, MESSAGE) \
  do {                                  \
    if (!(CONDITION)) {                 \
      log(MESSAGE);                     \
    }                                   \
  } while (0) // Line splicing is appropriate in macros
